/* ── 이슈 태그 ──
   시스템 추출: 파란 계열
   사용자 추가: 녹색 계열
── */
.issue-tag-area {
  padding: 8px 10px; min-height: 40px;
  display: flex; flex-wrap: wrap; gap: 5px; align-items: center;
}
/* 범례 */
.issue-legend {
  width: 100%; display: flex; gap: 12px;
  padding: 4px 10px 0;
  font-size: 11px; color: #888;
}
.issue-legend span { display: flex; align-items: center; gap: 4px; }
.legend-dot {
  width: 9px; height: 9px; border-radius: 50%; display: inline-block;
}
.legend-dot.sys  { background: #5b8def; }
.legend-dot.user { background: #27ae60; }

/* 공통 태그 베이스 */
.issue-tag {
  border-radius: 12px; padding: 3px 8px 3px 10px;
  font-size: 12px; display: inline-flex; align-items: center; gap: 4px;
  font-weight: 500;
}
/* 시스템(자동 추출) */
.issue-tag.sys {
  background: #e8f0fe; border: 1px solid #aac4f5; color: #1a55c4;
}
/* 사용자 추가 */
.issue-tag.user {
  background: #e6f7ee; border: 1px solid #82d4a0; color: #1a7a3a;
}
.issue-tag .del-btn {
  cursor: pointer; font-size: 14px; line-height: 1;
  background: none; border: none; padding: 0 1px;
}
.issue-tag.sys  .del-btn { color: #7ba7e8; }
.issue-tag.user .del-btn { color: #6ec48b; }
.issue-tag.sys  .del-btn:hover { color: #c0392b; }
.issue-tag.user .del-btn:hover { color: #c0392b; }

.issue-input-row {
  display: flex; gap: 5px; padding: 5px 10px 7px;
  border-top: 1px solid #eef0f5;
}
.issue-input-row input {
  flex: 1; padding: 3px 8px;
  border: 1px solid #ccc; border-radius: 3px;
  font-size: 12px; outline: none;
}
.issue-input-row input:focus { border-color: #2c4a7c; }
.issue-input-row button {
  padding: 3px 10px; background: #2c4a7c; color: #fff;
  border: none; border-radius: 3px; font-size: 12px; cursor: pointer;
}
.issue-input-row button:hover { background: #1e3460; }

/* ── 상담 요약 (폴딩) ── */
.summary-group { display: flex; flex-direction: column; }
.summary-item { border-bottom: 1px solid #e0e4ed; }
.summary-item:last-child { border-bottom: none; }

/* 클릭 가능한 서브 헤더 */
.summary-sub-title {
  display: flex; align-items: center; justify-content: space-between;
  font-size: 12px; font-weight: bold; color: #444;
  background: #f5f7fc;
  padding: 5px 10px;
  cursor: pointer;
  user-select: none;
  border-bottom: 1px solid transparent;
  transition: background 0.15s;
}
.summary-sub-title:hover { background: #eaecf5; }
.summary-sub-title.open { border-bottom-color: #e0e4ed; }

/* 폴딩 아이콘 */
.fold-icon {
  font-size: 11px; color: #888;
  transition: transform 0.2s;
  display: inline-block;
}
.summary-sub-title.open .fold-icon { transform: rotate(0deg); }
.summary-sub-title:not(.open) .fold-icon { transform: rotate(-90deg); }

/* 전체 요약 헤더 강조 */
.summary-sub-title.all-summary { background: #edf2fb; color: #2c4a7c; }
.summary-sub-title.all-summary:hover { background: #dce7f5; }

/* 요약 텍스트 영역 */
.summary-body {
  overflow: hidden;
  max-height: 0;
  transition: max-height 0.25s ease;
}
.summary-body.open {
  max-height: 200px;
}
.summary-text {
  font-size: 12px; color: #333; line-height: 1.6;
  padding: 6px 12px;
