  ta.style.height = Math.max(h, 60) + 'px';
  ta.style.maxHeight = '115px';

  el.style.display = 'none';
  el.parentNode.insertBefore(ta, el.nextSibling);
  ta.focus();
  ta.setSelectionRange(ta.value.length, ta.value.length);

  const hint = el.closest('.summary-body').previousElementSibling.querySelector('.summary-edit-hint');
  if (hint) { hint.textContent = 'Esc 또는 외부 클릭으로 저장'; hint.style.color = '#e09000'; }

  function save() {
    el.dataset.md = ta.value;
    el.innerHTML = marked.parse(ta.value);
    ta.remove();
    el.style.display = '';
    if (hint) { hint.textContent = '더블클릭하여 편집'; hint.style.color = ''; }
  }

  ta.addEventListener('blur', save);
  ta.addEventListener('keydown', e => {
    if (e.key === 'Escape') {
      ta.removeEventListener('blur', save);
      ta.remove();
      el.style.display = '';
      if (hint) { hint.textContent = '더블클릭하여 편집'; hint.style.color = ''; }
    }
  });
}

// 편집 중 Enter → 저장(blur), Escape → 취소
document.addEventListener('keydown', function(e) {
  const el = document.activeElement;
  if (!el.classList.contains('summary-text')) return;
  if (e.key === 'Escape') {
    el.blur();
  }
});
</script>
