Chart.js 레이더 초기화 (JS):
```javascript
const radarCtx = document.getElementById('evalRadarChart').getContext('2d');
const evalData = [
  { label: '공감 대응',  score: 7, desc: '기본 공감 표현 포함, 중도이사 우려 추가 설명 다소 부족' },
  { label: '언어 준수',  score: 10, desc: '금칙어·금지어 사용 없음, 고객 발화 내 금칙어 미감지' },
  { label: '상담 태도',  score: 8, desc: '안내 적극적이고 신속, 서류·절차 명확히 전달' },
  { label: '책임 이행', score: 9, desc: '책임 회피성 표현 없음, 해결 중심 응대' },
  { label: '발화 효율', score: 8, desc: '불필요 반복 발화 없음, 간결한 안내' },
];

new Chart(radarCtx, {
  type: 'radar',
  data: {
    labels: evalData.map(d => d.label),
    datasets: [{
      data: evalData.map(d => d.score),
      backgroundColor: 'rgba(44,74,124,0.15)',
      borderColor: '#2c4a7c',
      borderWidth: 2,
      pointBackgroundColor: '#2c4a7c',
      pointRadius: 3,
    }]
  },
  options: {
    responsive: true,
    maintainAspectRatio: true,
    plugins: { legend: { display: false } },
    scales: {
      r: {
        min: 0, max: 10,
        ticks: { stepSize: 2, font: { size: 9 }, backdropPadding: 2 },
        pointLabels: { font: { size: 10 }, color: '#333' },
        grid: { color: '#e0e3eb' },
        angleLines: { color: '#d0d5de' }
      }
    }
  }
});

// 근거 항목 렌더링
const legendBox = document.getElementById('radarLegend');
evalData.forEach(d => {
  const div = document.createElement('div');
  div.className = 'radar-item';
  div.innerHTML = `<div class="r-label">${d.label}<span class="r-score">${d.score}/10</span></div>
                   <div class="r-desc">${d.desc}</div>`;
  legendBox.appendChild(div);
});
```

