.edit-btn { color: #2c4a7c; }
.edit-btn:hover { background: #e8f0fe; }
.del-row-btn { color: #c0392b; }
.del-row-btn:hover { background: #ffe5e3; }
.row-edit-input { width:100%; padding:2px 6px; border:1px solid #2c4a7c; border-radius:3px; font-size:12.5px; outline:none; }

/* 상담요약 간략화 */
.summary-plain-item { padding: 7px 10px; border-bottom: 1px solid #eef0f5; }
.summary-plain-item:last-child { border-bottom: none; }
.summary-plain-label { font-size: 11px; font-weight: bold; color: #888; margin-bottom: 3px; }
.summary-plain-text { font-size: 12.5px; color: #333; line-height: 1.6; cursor: text; padding: 3px 4px; border-radius: 3px; }
.summary-plain-text:hover { background: #f5f7fb; }

/* 긍부정 탭 */
.sent-tabs { display:flex; gap:3px; padding:4px 8px 0; border-bottom:1px solid #d0d5de; }
.sent-tab { padding:3px 10px; border:1px solid #ccc; border-bottom:none; border-radius:3px 3px 0 0; background:#e8edf5; cursor:pointer; font-size:12px; color:#555; }
