## Step 4. JS 변경

**제거:** `toggleSummary()` 함수

**수정:** `startEdit()` — `.closest('.summary-body')` 참조를 `.closest('.summary-plain-item')` 기준으로 변경

**추가:**
```javascript
// 행 인라인 수정
function startRowEdit(btn) {
  const td = btn.closest('tr').querySelector('.editable-cell');
  const span = td.querySelector('.cell-text');
  if (td.querySelector('.row-edit-input')) return;
  const input = document.createElement('input');
  input.className = 'row-edit-input';
  input.value = span.textContent;
  span.style.display = 'none';
  td.appendChild(input);
  input.focus();
  function save() { span.textContent = input.value; span.style.display = ''; input.remove(); }
  input.addEventListener('blur', save);
  input.addEventListener('keydown', e => {
    if (e.key === 'Enter') input.blur();
    if (e.key === 'Escape') { input.remove(); span.style.display = ''; }
  });
}

// 행 삭제 + 순위 재정렬
function deleteRow(btn) {
  const tr = btn.closest('tr');
  const tbody = tr.closest('tbody');
  tr.remove();
  tbody.querySelectorAll('tr').forEach((r, i) => {
    const rankCell = r.querySelector('.rank');
    if (rankCell) rankCell.textContent = i + 1;
  });
}

// 긍부정 탭 전환
function switchSentTab(tabEl, panelId) {
  tabEl.closest('.section').querySelectorAll('.sent-tab').forEach(t => t.classList.remove('active'));
  tabEl.closest('.section').querySelectorAll('.sent-panel').forEach(p => p.classList.remove('active'));
  tabEl.classList.add('active');
  document.getElementById(panelId).classList.add('active');
}
```

