.sent-tab.active { background:#fff; border-color:#2c4a7c; color:#2c4a7c; font-weight:bold; border-bottom:1px solid #fff; margin-bottom:-1px; }
.sent-panel { display:none; }
.sent-panel.active { display:block; }

/* 레이더 레이아웃 */
.eval-radar-wrap { flex:1; overflow-y:auto; padding:8px 10px; }
.radar-layout { display:flex; gap:10px; align-items:flex-start; }
