});

// 레이더 그래프
const evalData = [
  { label:'공감 대응', score:7, desc:'기본 공감 포함, 중도이사 우려에 추가 설명 다소 부족' },
  { label:'언어 준수', score:10, desc:'금칙어·금지어 사용 없음, 고객 발화 내 금칙어 미감지' },
  { label:'상담 태도', score:8,  desc:'안내 적극적·신속, 서류·절차 명확히 전달' },
  { label:'책임 이행', score:9,  desc:'책임 회피 표현 없음, 해결 중심 응대' },
  { label:'발화 효율', score:8,  desc:'불필요 반복 발화 없음, 간결한 안내' },
];
new Chart(document.getElementById('evalRadarChart').getContext('2d'), {
